// Normalize Supabase response and check if we have contacts
const allItems = $input.all();
const contacts = [];

for (const item of allItems) {
  if (item.json && item.json.id) {
    contacts.push(item.json);
  } else if (Array.isArray(item.json)) {
    for (const c of item.json) {
      if (c && c.id) contacts.push(c);
    }
  }
}

if (contacts.length === 0) {
  return [{ json: { has_contacts: false, contact_count: 0, contacts: [] } }];
}

return [{ json: { has_contacts: true, contact_count: contacts.length, contacts: contacts } }];

// Build batches of profile URLs for Apify scraping
// Batch into groups of 8 to stay under 300s timeout

const data = $input.first().json;
const contacts = data.contacts || [];

// Validate LinkedIn URLs
const validContacts = contacts.filter(c => 
  c.linkedin_url && c.linkedin_url.startsWith('https://www.linkedin.com/in/')
);

// Build batches of 8
const batchSize = 8;
const batches = [];
for (let i = 0; i < validContacts.length; i += batchSize) {
  const batch = validContacts.slice(i, i + batchSize);
  batches.push({
    profileUrls: batch.map(c => c.linkedin_url),
    contacts: batch
  });
}

if (batches.length === 0) {
  return [{ json: { has_batches: false, batch_count: 0 } }];
}

// Output each batch as a separate item for SplitInBatches
return batches.map((batch, i) => ({
  json: {
    has_batches: true,
    batch_index: i,
    batch_count: batches.length,
    profileUrls: batch.profileUrls,
    contacts: batch.contacts,
    all_contacts: validContacts
  }
}));

// Filter scraped posts to last 24 hours and min engagement threshold
// Map each post back to its contact from the engagement_network

const scrapedItems = $input.all();
const batchData = $('Scrape Batches').first().json;
const contacts = batchData.contacts || [];

// Build lookup by profile URL / publicIdentifier
const contactMap = {};
for (const c of contacts) {
  if (c.linkedin_url) {
    // Extract identifier from URL
    const match = c.linkedin_url.match(/linkedin\.com\/in\/([^\/\?]+)/);
    if (match) {
      contactMap[match[1].toLowerCase()] = c;
    }
    contactMap[c.linkedin_url.toLowerCase()] = c;
  }
}

const now = new Date();
const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const MIN_ENGAGEMENT = 5;

const filteredPosts = [];

for (const item of scrapedItems) {
  const post = item.json;
  if (!post || !post.content) continue;

  // Check recency (last 24 hours)
  const postedAt = post.postedAt ? new Date(post.postedAt) : null;
  if (!postedAt || postedAt < oneDayAgo) continue;

  // Check minimum engagement
  const likes = post.likes || 0;
  const comments = post.comments || 0;
  const shares = post.shares || 0;
  const totalEngagement = likes + comments + shares;
  if (totalEngagement < MIN_ENGAGEMENT) continue;

  // Match to contact
  let matchedContact = null;
  const pubId = (post.publicIdentifier || '').toLowerCase();
  const linkedinUrl = (post.linkedinUrl || '').toLowerCase();

  if (pubId && contactMap[pubId]) {
    matchedContact = contactMap[pubId];
  } else if (linkedinUrl) {
    const urlMatch = linkedinUrl.match(/linkedin\.com\/in\/([^\/\?]+)/);
    if (urlMatch && contactMap[urlMatch[1].toLowerCase()]) {
      matchedContact = contactMap[urlMatch[1].toLowerCase()];
    }
  }

  filteredPosts.push({
    post_url: post.linkedinUrl || post.url || '',
    post_content: (post.content || '').substring(0, 2000),
    post_content_short: (post.content || '').substring(0, 500),
    author_name: post.name || (matchedContact ? matchedContact.linkedin_name : 'Unknown'),
    author_url: matchedContact ? matchedContact.linkedin_url : '',
    author_followers: matchedContact ? matchedContact.follower_count : null,
    contact_id: matchedContact ? matchedContact.id : null,
    contact_tier: matchedContact ? matchedContact.tier : null,
    likes: likes,
    comments: comments,
    shares: shares,
    total_engagement: totalEngagement,
    posted_at: post.postedAt
  });
}

// Store for accumulation across batches
return [{ json: { filtered_posts: filteredPosts, batch_post_count: filteredPosts.length } }];

// Rank all filtered posts from all batches and select top 7
// This runs after SplitInBatches completes (done output)

// Collect all filtered_posts from all batch iterations
const allBatchResults = $('Filter Recent Posts').all();
let allPosts = [];

for (const item of allBatchResults) {
  const posts = item.json.filtered_posts || [];
  allPosts = allPosts.concat(posts);
}

// Deduplicate by post_url
const seen = new Set();
const uniquePosts = allPosts.filter(p => {
  const key = p.post_url || p.post_content_short;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Rank by engagement score with tier bonus
// (likes * 1) + (comments * 3) + (shares * 2) + tier_1 bonus (+10)
const ranked = uniquePosts.map(p => ({
  ...p,
  engagement_score: (p.likes * 1) + (p.comments * 3) + (p.shares * 2) + (p.contact_tier === 'tier_1' ? 10 : 0)
}));

// Sort by engagement score descending
ranked.sort((a, b) => b.engagement_score - a.engagement_score);

// Select top 7 (if fewer than 5, take all)
const selected = ranked.slice(0, 7);

if (selected.length === 0) {
  return [{ json: { has_posts: false, selected_count: 0, selected_posts: [] } }];
}

return [{ json: { has_posts: true, selected_count: selected.length, selected_posts: selected } }];

// Prepare posts for Claude comment generation
// Output each post as a separate item for batch processing

const data = $input.first().json;
const posts = data.selected_posts || [];

return posts.map((post, i) => ({
  json: {
    ...post,
    post_index: i,
    total_posts: posts.length
  }
}));

// Parse Claude comment suggestions and build digest item
const claudeResponse = $input.first().json;
const postData = $('Comment Gen (Batch)').first().json;

let suggestions;
try {
  const responseText = claudeResponse.content?.[0]?.text || '{}';
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  suggestions = parsed.suggestions || [];
} catch (e) {
  suggestions = [
    { style: 'insight', text: 'Great perspective on this topic. The intersection with AI compliance is particularly relevant right now.' },
    { style: 'question', text: 'How are you seeing organizations adapt their approach to this? Curious about what\'s working in practice.' }
  ];
}

const digestDate = $('Build Date & Run ID').first().json.digest_date;

return [{
  json: {
    digest_date: digestDate,
    digest_type: 'daily',
    target_post_url: postData.post_url || null,
    target_post_content: (postData.post_content || '').substring(0, 500),
    target_author: postData.author_name || null,
    target_author_url: postData.author_url || null,
    target_author_followers: postData.author_followers || null,
    network_contact_id: postData.contact_id || null,
    post_engagement: {
      likes: postData.likes || 0,
      comments: postData.comments || 0,
      shares: postData.shares || 0
    },
    comment_suggestions: suggestions,
    status: 'pending'
  }
}];

// After all digest items stored, update last_monitored on scraped contacts
// and prepare summary for Slack notification

const allDigestItems = $('Parse Comment Suggestions').all();
const allContacts = $('Build Profile URL Batches').first().json.all_contacts || [];

// Get unique contact IDs that were scraped
const contactIds = [...new Set(allContacts.map(c => c.id).filter(Boolean))];

// Build digest summary for Slack
const digestItems = allDigestItems.map(item => item.json);

return [{
  json: {
    contact_ids: contactIds,
    digest_count: digestItems.length,
    digest_items: digestItems,
    digest_date: $('Build Date & Run ID').first().json.digest_date
  }
}];

