// Check if today has a scheduled/approved post
const response = $input.first().json;
let slots = [];

if (Array.isArray(response)) {
  slots = response;
} else if (response && response.id) {
  slots = [response];
}

// Find first slot with a post_id
const slotWithPost = slots.find(s => s.post_id !== null && s.post_id !== undefined);

if (!slotWithPost) {
  return [{
    json: {
      has_post: false,
      skip_reason: slots.length === 0 ? 'No calendar slot for today' : 'Calendar slot has no linked post_id'
    }
  }];
}

return [{
  json: {
    has_post: true,
    post_id: slotWithPost.post_id,
    series: slotWithPost.series || '',
    pillar: slotWithPost.pillar || ''
  }
}];

// Score contacts for warming relevance based on upcoming post topic
// Algorithm from RESEARCH.md:
//   - Same category as post topic: +3
//   - Tier 1: +2, Tier 2: +1
//   - Not engaged in last 48h: +1
//   - Select top 4

const allItems = $input.all();
const contacts = [];

for (const item of allItems) {
  if (item.json && item.json.id) {
    contacts.push(item.json);
  } else if (Array.isArray(item.json)) {
    for (const c of item.json) {
      if (c && c.id) contacts.push(c);
    }
  }
}

const postData = $('Fetch Post Details').first().json;
const calendarData = $('Check Calendar Slot').first().json;

// Determine post topic category from series/pillar
const postSeries = postData.series || calendarData.series || '';
const postPillar = postData.pillar || calendarData.pillar || '';
const postText = (postData.hook_text || '') + ' ' + (postData.full_text || '').substring(0, 200);

// Map series to likely categories
const seriesCategoryMap = {
  'not_being_told': ['ai_policy', 'employment_attorney'],
  'compliance_radar': ['employment_attorney', 'hr_leader'],
  'ask_ai_guy': ['hr_tech', 'ai_policy'],
  'flex': ['hr_leader', 'hr_tech', 'journalist']
};

const relevantCategories = seriesCategoryMap[postSeries] || ['hr_leader', 'hr_tech'];

const now = new Date();
const twoDaysAgo = new Date(now.getTime() - 48 * 60 * 60 * 1000);

// Score each contact
const scored = contacts
  .filter(c => c.linkedin_url && c.linkedin_url.startsWith('https://www.linkedin.com/in/'))
  .map(c => {
    let score = 0;

    // Same category as post topic
    if (c.category && relevantCategories.includes(c.category)) score += 3;

    // Tier bonus
    if (c.tier === 'tier_1') score += 2;
    else if (c.tier === 'tier_2') score += 1;

    // Not engaged recently (avoid over-engagement)
    const lastEngaged = c.last_engaged ? new Date(c.last_engaged) : null;
    if (!lastEngaged || lastEngaged < twoDaysAgo) score += 1;

    return { ...c, warming_score: score };
  });

// Sort by score descending, take top 4
scored.sort((a, b) => b.warming_score - a.warming_score);
const selected = scored.slice(0, 4);

if (selected.length === 0) {
  return [{ json: { has_targets: false, target_count: 0 } }];
}

return [{
  json: {
    has_targets: true,
    target_count: selected.length,
    warming_targets: selected,
    post_context: {
      hook_text: postData.hook_text || '',
      series: postSeries,
      pillar: postPillar,
      post_summary: postText.substring(0, 300)
    }
  }
}];

// Filter warming posts: most recent post per contact (last 48h)
// Select the best post per contact (highest engagement)

const scrapedItems = $input.all();
const targetData = $('Select Warming Targets').first().json;
const warmingTargets = targetData.warming_targets || [];

// Build contact lookup
const contactMap = {};
for (const t of warmingTargets) {
  if (t.linkedin_url) {
    const match = t.linkedin_url.match(/linkedin\.com\/in\/([^\/\?]+)/);
    if (match) contactMap[match[1].toLowerCase()] = t;
  }
}

const now = new Date();
const twoDaysAgo = new Date(now.getTime() - 48 * 60 * 60 * 1000);

// Group posts by contact
const postsByContact = {};

for (const item of scrapedItems) {
  const post = item.json;
  if (!post || !post.content) continue;

  const postedAt = post.postedAt ? new Date(post.postedAt) : null;
  if (!postedAt || postedAt < twoDaysAgo) continue;

  // Match to contact
  const pubId = (post.publicIdentifier || '').toLowerCase();
  let contact = null;
  if (pubId && contactMap[pubId]) {
    contact = contactMap[pubId];
  }

  if (!contact) continue;

  const contactKey = contact.id;
  const engagement = (post.likes || 0) + (post.comments || 0) * 3 + (post.shares || 0) * 2;

  if (!postsByContact[contactKey] || engagement > postsByContact[contactKey].engagement) {
    postsByContact[contactKey] = {
      post_url: post.linkedinUrl || post.url || '',
      post_content: (post.content || '').substring(0, 2000),
      post_content_short: (post.content || '').substring(0, 500),
      author_name: contact.linkedin_name,
      author_url: contact.linkedin_url,
      author_followers: contact.follower_count,
      contact_id: contact.id,
      likes: post.likes || 0,
      comments: post.comments || 0,
      shares: post.shares || 0,
      engagement: engagement
    };
  }
}

const selectedPosts = Object.values(postsByContact);

return [{
  json: {
    warming_posts: selectedPosts,
    warming_post_count: selectedPosts.length,
    post_context: targetData.post_context
  }
}];

// Prepare warming posts for Claude comment generation
// Output each post as separate item

const data = $input.first().json;
const posts = data.warming_posts || [];
const postContext = data.post_context || {};

return posts.map((post, i) => ({
  json: {
    ...post,
    post_context: postContext,
    post_index: i,
    total_warming_posts: posts.length
  }
}));

// Parse warming comment suggestions and build warming digest item
const claudeResponse = $input.first().json;
const postData = $('Warming Comment (Batch)').first().json;

let suggestions;
try {
  const responseText = claudeResponse.content?.[0]?.text || '{}';
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  suggestions = parsed.suggestions || [];
} catch (e) {
  suggestions = [
    { style: 'insight', text: 'Interesting perspective -- we have been exploring similar territory at IAML.' },
    { style: 'question', text: 'How are you thinking about the AI implications here? Would love to hear more.' }
  ];
}

const today = $('Build Warming Date').first().json.today;
const postContext = postData.post_context || {};

return [{
  json: {
    digest_date: today,
    digest_type: 'warming',
    target_post_url: postData.post_url || null,
    target_post_content: (postData.post_content || '').substring(0, 500),
    target_author: postData.author_name || null,
    target_author_url: postData.author_url || null,
    target_author_followers: postData.author_followers || null,
    network_contact_id: postData.contact_id || null,
    post_engagement: {
      likes: postData.likes || 0,
      comments: postData.comments || 0,
      shares: postData.shares || 0
    },
    comment_suggestions: suggestions,
    status: 'pending',
    warming_context: 'Upcoming post: ' + (postContext.hook_text || '') + ' [' + (postContext.series || '') + ']'
  }
}];

// After all warming items stored, build summary for Slack

const allWarmingItems = $('Parse Warming Suggestions').all();
const warmingItems = allWarmingItems.map(item => item.json);
const postContext = $('Select Warming Targets').first().json.post_context || {};

return [{
  json: {
    warming_count: warmingItems.length,
    warming_items: warmingItems,
    post_context: postContext,
    today: $('Build Warming Date').first().json.today
  }
}];

